export function getEpcPropertiesByPostcode(prefix: string): EpcTargetProperty[] {
  const upper = prefix.toUpperCase().trim();
  return EPC_TARGET_PROPERTIES.filter(p => p.postcode.startsWith(upper));
}

export function getEpcPropertiesBySubstation(substationId: string): EpcTargetProperty[] {
  return EPC_TARGET_PROPERTIES.filter(p => p.nearestSubstationId === substationId);
}

export function getTopEpcProspects(limit = 50): EpcTargetProperty[] {
  return EPC_TARGET_PROPERTIES.slice(0, limit);
}
